operation.search:
// @todo Separate the sprintf?
if (empty($regOptions['email']) || !filter_var($regOptions['email'], FILTER_VALIDATE_EMAIL) || strlen($regOptions['email']) > 255)
	$reg_errors[] = array('lang', 'profile_error_bad_email');

operation.add:
// Lets restrict some email providers and domains
$is_bad_email = empty($regOptions['email']) || !filter_var($regOptions['email'], FILTER_VALIDATE_EMAIL) || strlen($regOptions['email']) > 255;

if (!empty($modSettings['enable_restrict_EmailProvider']) && !$is_bad_email)
{
   $email_domain = strtolower(substr(strrchr($regOptions['email'], "@"), 1));

   // 1. Check Restricted Providers
   if (!empty($modSettings['restricted_provider']))
   {
      $restricted_provider = explode(',', strtolower($modSettings['restricted_provider']));
      foreach ($restricted_provider as $provider)
      {
         $provider = trim($provider);
         if (!empty($provider) && stripos($regOptions['email'], $provider) !== false)
            fatal_error(sprintf($txt['restricted'], $regOptions['username']), false);
      }
   }

   // 2. Check Restricted Domains/TLDs
   if (!empty($modSettings['restricted_domain']))
   {
      $restricted_domain = explode(',', strtolower($modSettings['restricted_domain']));
      foreach ($restricted_domain as $domain)
      {
         $domain = trim($domain);
         if (!empty($domain))
         {
            if ($domain[0] !== '.') $domain = '.' . $domain;
            if (substr('.' . $email_domain, -strlen($domain)) === $domain)
               fatal_error(sprintf($txt['restricted_domain_msg'], $regOptions['username']), false);
         }
      }
   }

   // 3. Check Accepted Providers
   if (!empty($modSettings['accepted_provider']))
   {
      $accepted_provider = explode(',', strtolower($modSettings['accepted_provider']));
      $provider_matched = false;
      $has_valid_providers = false;
      foreach ($accepted_provider as $provider)
      {
         $provider = trim($provider);
         if (!empty($provider))
         {
            $has_valid_providers = true;
            if (stripos($regOptions['email'], $provider) !== false)
            {
               $provider_matched = true;
               break;
            }
         }
      }
      if ($has_valid_providers && !$provider_matched)
         fatal_error(sprintf($txt['restricted'], $regOptions['username']), false);
   }

   // 4. Check Accepted Domains/TLDs
   if (!empty($modSettings['accepted_domain']))
   {
      $accepted_domain = explode(',', strtolower($modSettings['accepted_domain']));
      $domain_matched = false;
      $has_valid_domains = false;
      foreach ($accepted_domain as $domain)
      {
         $domain = trim($domain);
         if (!empty($domain))
         {
            $has_valid_domains = true;
            if ($domain[0] !== '.') $domain = '.' . $domain;
            if (substr('.' . $email_domain, -strlen($domain)) === $domain)
            {
               $domain_matched = true;
               break;
            }
         }
      }
      if ($has_valid_domains && !$domain_matched)
         fatal_error(sprintf($txt['restricted_domain_msg'], $regOptions['username']), false);
   }

   // 5. Check pattern restrictions
   $email_local = substr($regOptions['email'], 0, strrpos($regOptions['email'], '@'));

   // Max dots
   if (!empty($modSettings['restrict_max_dots']) && $modSettings['restrict_max_dots'] > 0 && substr_count($email_local, '.') > $modSettings['restrict_max_dots'])
      fatal_error(sprintf($txt['restricted_pattern'], $regOptions['username']), false);

   // Max numbers
   if (!empty($modSettings['restrict_max_numbers']) && $modSettings['restrict_max_numbers'] > 0 && preg_match_all('/[0-9]/', $email_local) > $modSettings['restrict_max_numbers'])
      fatal_error(sprintf($txt['restricted_pattern'], $regOptions['username']), false);

   // Max hyphens
   if (!empty($modSettings['restrict_max_hyphens']) && $modSettings['restrict_max_hyphens'] > 0 && substr_count($email_local, '-') > $modSettings['restrict_max_hyphens'])
      fatal_error(sprintf($txt['restricted_pattern'], $regOptions['username']), false);

   // Max underscores
   if (!empty($modSettings['restrict_max_underscores']) && $modSettings['restrict_max_underscores'] > 0 && substr_count($email_local, '_') > $modSettings['restrict_max_underscores'])
      fatal_error(sprintf($txt['restricted_pattern'], $regOptions['username']), false);
}

// @todo Separate the sprintf?
if ($is_bad_email)
   $reg_errors[] = array('lang', 'profile_error_bad_email');

// Start Restrict Email Mod
function ShowRestrictEmail($return_config = false)
{
	global $txt, $scripturl, $context, $settings, $sc, $modSettings, $boarddir, $sourcedir;

	$config_vars = array(
			array('check', 'enable_restrict_EmailProvider',
			&$txt['enable_restrict_EmailProvider']), 
			'',
			array('large_text', 'restricted_provider', '8', 
			&$txt['restricted_provider'], 'cols' => 30),
			array('large_text', 'accepted_provider', '8', 
			&$txt['accepted_provider'], 'cols' => 30),
			array('large_text', 'restricted_domain', '8', 
			&$txt['restricted_domain'], 'cols' => 30),
			array('large_text', 'accepted_domain', '8', 
			&$txt['accepted_domain'], 'cols' => 30),

			// Pattern Restrictions
			'',
			array('int', 'restrict_max_dots', 
			&$txt['restrict_max_dots']),
			array('int', 'restrict_max_numbers', 
			&$txt['restrict_max_numbers']),
			array('int', 'restrict_max_hyphens', 
			&$txt['restrict_max_hyphens']),
			array('int', 'restrict_max_underscores', 
			&$txt['restrict_max_underscores']),
	);

	if ($return_config)
		return $config_vars;

	$context['post_url'] = $scripturl . '?action=admin;area=modsettings;save;sa=restrictemail';
	$context['settings_title'] = $txt['restrictemail_title'];

	// Saving?
	if (isset($_GET['save']))
	{
		checkSession();
		$save_vars = $config_vars;
		saveDBSettings($save_vars);
		redirectexit('action=admin;area=modsettings;sa=restrictemail');
	}

	prepareDBSettingContext($config_vars);
}
// End Restrict Email Mod
